type RTipo = Riesgo['tipo'];
type REstado = Riesgo['estado'];

const calcularNivel = (prob: number, imp: number): Riesgo['nivel'] => {
  const score = prob * imp;
  if (score >= 15) return 'critico';
  if (score >= 8) return 'alto';
  if (score >= 4) return 'medio';
  return 'bajo';
