301 |           const row: Record<string, any> = {};
302 |           COL_MATERIALES.forEach(col => { row[col.label] = col.fn(m); });
303 |           return row;
304 |         });
305 |         const wsMat = XLSX.utils.json_to_sheet(matData);
306 |         XLSX.utils.book_append_sheet(wb, wsMat, 'Materiales');
307 | 
308 |         // Hoja: Presupuestos
309 |         const ctx = { proyectos };
310 |         const presData = presupuestos.map(p => {
311 |           const row: Record<string, any> = {};
312 |           COL_PRESUPUESTOS.forEach(col => { row[col.label] = col.fn(p, ctx); });
313 |           return row;
314 |         });
315 |         const wsPres = XLSX.utils.json_to_sheet(presData);
316 |         XLSX.utils.book_append_sheet(wb, wsPres, 'Presupuestos');
317 | 
318 |         // Hoja: EERR (Estado de Resultados por Proyecto)
319 |         const eerrData = proyectos.map(p => {
320 |           const movsProy = movimientos.filter(m => m.proyectoId === p.id);
321 |           const ingresos = movsProy.filter(m => m.tipo === 'ingreso').reduce((a, m) => a + (m.costoTotal ?? m.monto), 0);
322 |           const costosDirectos = movsProy.filter(m => m.tipo === 'gasto' || m.tipo === 'egreso').reduce((a, m) => a + (m.costoTotal ?? m.monto), 0);
323 |           const utilidadBruta = ingresos - costosDirectos;
324 |           const gastosAdmin = costosDirectos * 0.10; // 10% administración estimada
325 |           const utilidadNeta = utilidadBruta - gastosAdmin;
326 |           const margenBruto = ingresos > 0 ? (utilidadBruta / ingresos) * 100 : 0;
327 |           const margenNeto = ingresos > 0 ? (utilidadNeta / ingresos) * 100 : 0;
328 |           const roi = costosDirectos > 0 ? ((utilidadNeta / costosDirectos) * 100) : 0;
329 |           return {
330 |             'Proyecto': p.nombre,
331 |             'Ingresos (Q)': Math.round(ingresos * 100) / 100,
332 |             'Costos Directos (Q)': Math.round(costosDirectos * 100) / 100,
333 |             'Utilidad Bruta (Q)': Math.round(utilidadBruta * 100) / 100,
334 |             'Gastos Administración (Q)': Math.round(gastosAdmin * 100) / 100,
335 |             'Utilidad Neta (Q)': Math.round(utilidadNeta * 100) / 100,
336 |             'Margen Bruto %': Math.round(margenBruto * 10) / 10,
337 |             'Margen Neto %': Math.round(margenNeto * 10) / 10,
338 |             'ROI %': Math.round(roi * 10) / 10,
339 |           };
340 |         });
341 |         const wsEERR = XLSX.utils.json_to_sheet(eerrData);
342 |         XLSX.utils.book_append_sheet(wb, wsEERR, 'EERR');
343 | 
344 |         // Auto-size column widths
345 |         [wsProy, wsMov, wsEmp, wsMat, wsPres, wsEERR].forEach(ws => {
346 |           if (!ws['!cols']) {
347 |             const range = XLSX.utils.decode_range(ws['!ref'] || 'A1');
348 |             ws['!cols'] = [];
349 |             for (let c = range.s.c; c <= range.e.c; c++) {
350 |               let maxLen = 0;
351 |               for (let r = range.s.r; r <= range.e.r; r++) {
352 |                 const cell = ws[XLSX.utils.encode_cell({ r, c })];
353 |                 if (cell && typeof cell.v === 'string') maxLen = Math.max(maxLen, cell.v.length);
354 |               }
355 |               ws['!cols'].push({ wch: Math.min(Math.max(maxLen + 2, 12), 40) });
356 |             }
357 |           }
358 |         });
359 | 
360 |         XLSX.writeFile(wb, `construsmart-export-${todayISO()}.xlsx`);
361 |         toast.success('✅ Excel exportado exitosamente (6 hojas: EERR incluido)');
362 |       } catch (err) {
363 |         safeLogger.error(new Error('XLSX error: ' + (err as Error).message));
364 |         toast.error('Error al exportar Excel');
365 |       }
366 |       setExportando(null);
367 |     }, 500);
368 |   }, [proyectos, movimientos, empleados, materiales, presupuestos]);
